import json
import boto3
from botocore.exceptions import ClientError

# Initialize SQS client
sqs = boto3.client('sqs')

# Define message processor function
def process_message(message):
    # Parse message body
    message_body = json.loads(message['Body'])
    
    # Handle different message types dynamically
    if message_body['type'] == 'job':
        # Execute job processing actions
        print("Processing job...")
    elif message_body['type'] == 'notification':
        # Execute notification processing actions
        print("Processing notification...")
    else:
        # Default action
        print("Received unknown message type. Ignoring...")

# Define SQS queue URL
queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/my-queue'

# Poll for messages from the SQS queue
while True:
    try:
        # Receive message from the queue
        response = sqs.receive_message(QueueUrl=queue_url, MaxNumberOfMessages=1)
        
        # Process message if there is one
        if 'Messages' in response:
            message = response['Messages'][0]
            
            # Parse message body and execute actions based on message content
            process_message(message)
            
            # Delete processed message from the queue
            sqs.delete_message(QueueUrl=queue_url, ReceiptHandle=message['ReceiptHandle'])
        else:
            print("No messages available in the queue.")
    except ClientError as e:
        print(e)